const spendQuarter = quarters => {
  const spent = (quarters.filter(q => q).length + 1) % 5;
  return [...range(spent).map(_ => true), ...range(4 - spent).map(_ => false)];
};

const quarterReducer = (cal, monthIndex, day) => {
  return { ...cal,
    months: { ...cal.months,
      [monthIndex]: { ...cal.months[monthIndex],
        days: cal.months[monthIndex].days.map(d => {
          if (d.number === day.number) {
            d.quarters = spendQuarter(d.quarters);
          }

          return d;
        })
      }
    }
  };
};

